    public DataGridColumn<TItem> Column { get; init; } = default!;
    public object? Value { get; set; }
    public Action ValueChanged { get; init; } = default!;
}

@namespace Lumeo
@typeparam TItem

@code {
    [CascadingParameter] private DataGrid<TItem>? ParentGrid { get; set; }
    // Set by the enclosing <DataGridColumnGroup>, when present. Forwarded to the
    // registered DataGridColumn so the header can emit the spanning parent <th>.
    [CascadingParameter(Name = "ColumnGroupId")] private string? ColumnGroupId { get; set; }

    [Parameter] public string? Title { get; set; }
    [Parameter] public string? Field { get; set; }
    [Parameter] public Func<TItem, object?>? FieldSelector { get; set; }
    [Parameter] public double? Width { get; set; }
    [Parameter] public bool Sortable { get; set; }
    [Parameter] public bool Filterable { get; set; }
    [Parameter] public bool Resizable { get; set; } = true;
    [Parameter] public DataGridFilterType FilterType { get; set; } = DataGridFilterType.Text;
    [Parameter] public AggregateType Aggregate { get; set; } = AggregateType.None;
    [Parameter] public string? Format { get; set; }
    /// <summary>Optional .NET format string for the footer aggregate strip — overrides
    /// <see cref="Format"/> for the totals row only. Useful when the cell format differs
    /// from the desired totals format (e.g. cells <c>"C2"</c>, totals <c>"N0"</c>).</summary>
    [Parameter] public string? FooterFormat { get; set; }
    [Parameter] public PinDirection Pin { get; set; } = PinDirection.None;
    [Parameter] public RenderFragment<TItem>? CellTemplate { get; set; }
    [Parameter] public RenderFragment? HeaderTemplate { get; set; }
    [Parameter] public RenderFragment<CellEditContext<TItem>>? EditTemplate { get; set; }
    [Parameter] public double? MinWidth { get; set; }
    [Parameter] public double? MaxWidth { get; set; }
    [Parameter] public bool Pinnable { get; set; }
    [Parameter] public bool Groupable { get; set; }
    [Parameter] public bool Reorderable { get; set; } = true;
    [Parameter] public Func<TItem, string>? CellClass { get; set; }
    [Parameter] public string? HeaderCssClass { get; set; }
    [Parameter] public Comparison<object?>? CustomSort { get; set; }
    [Parameter] public List<FilterOption>? FilterOptions { get; set; }
    [Parameter] public List<FilterOperator>? Operators { get; set; }
    [Parameter] public RenderFragment<DataGridFilterTemplateContext>? FilterTemplate { get; set; }
    [Parameter] public string? Class { get; set; }

    /// <summary>
    /// Two-way bindable column visibility. Seeds the registered column's initial
    /// visibility and lets a consumer show/hide the column programmatically via
    /// <c>@bind-Visible</c>. When the user toggles the column through the built-in
    /// column-chooser, <see cref="VisibleChanged"/> fires so the bound value follows.
    /// Default <c>true</c>.
    /// </summary>
    [Parameter] public bool Visible { get; set; } = true;

    /// <summary>Fires when the column's visibility changes through the built-in UI —
    /// the callback half of <see cref="Visible"/>'s two-way binding.</summary>
    [Parameter] public EventCallback<bool> VisibleChanged { get; set; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Stable key of the column this def registered (Field when set, else the
    // generated column Id) plus the last Visible value we pushed to the grid — used
    // to detect consumer-driven @bind-Visible changes without re-registering.
    private string? _registeredKey;
    private bool _lastVisibleParam;

    protected override void OnInitialized() => Register();

    protected override void OnParametersSet()
    {
        // Consumer-driven visibility: when the bound Visible parameter changes after
        // registration, push it straight into the already-registered column. We do
        // NOT re-register (that bumped the layout-autosave generation on every
        // cascading-context refresh — see the note above Register) and we do NOT
        // fire VisibleChanged (this direction is already the source of truth).
        if (_registeredKey is not null && Visible != _lastVisibleParam)
        {
            _lastVisibleParam = Visible;
            ParentGrid?.SetColumnVisibility(_registeredKey, Visible);
        }
    }

    // NOTE: OnParametersSet was briefly wired to call Register() so per-column
    // flags (Sortable / Filterable / Pinnable) updated reactively when bound
    // to host-level state — but it re-registered on every cascading-context
    // refresh and bumped the layout autosave generation in a tight loop,
    // breaking the debounce window. Reverted: columns register once on
    // initialization, host-level toggles need an explicit grid refresh
    // (e.g. swap the @key on the grid).

    private void Register()
    {
        var column = new DataGridColumn<TItem>
        {
            Title = Title,
            Field = Field,
            FieldSelector = FieldSelector,
            Width = Width,
            Sortable = Sortable,
            Filterable = Filterable,
            Resizable = Resizable,
            FilterType = FilterType,
            Aggregate = Aggregate,
            Format = Format,
            FooterFormat = FooterFormat,
            ColumnGroupId = ColumnGroupId,
            Pin = Pin,
            CellTemplate = CellTemplate,
            HeaderTemplate = HeaderTemplate,
            EditTemplate = EditTemplate,
            FilterOptions = FilterOptions,
            Operators = Operators,
            FilterTemplate = FilterTemplate,
            MinWidth = MinWidth,
            MaxWidth = MaxWidth,
            Pinnable = Pinnable,
            Groupable = Groupable,
            Reorderable = Reorderable,
            CellClass = CellClass,
            HeaderCssClass = HeaderCssClass,
            CustomSort = CustomSort,
            CssClass = Class,
            Visible = Visible,
            VisibleChanged = VisibleChanged
        };

        // Capture the stable key + seed the change-tracking baseline BEFORE handing
        // the column to the grid, so OnParametersSet can diff future @bind-Visible
        // changes against it. Field-less columns key on the generated Id.
        _registeredKey = !string.IsNullOrWhiteSpace(Field) ? Field : column.Id;
        _lastVisibleParam = Visible;

        ParentGrid?.AddColumnDef(column);
    }
}

@namespace Lumeo
@typeparam TItem
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (Column?.FilterTemplate is not null)
    {
        <div class="p-3 space-y-3" data-slot="datagrid-filter-custom">
            @Column.FilterTemplate(new DataGridFilterTemplateContext(
                Column.Field,
                CurrentFilter,
                async desc => await OnApply.InvokeAsync(desc)))
        </div>
    }
    else
    {
    <div class="p-3 space-y-3">
        <div class="text-xs font-medium text-muted-foreground uppercase tracking-wider">
            @L["Filter.FilterTitle", Column?.Title ?? ""]
        </div>

        @if (Column?.FilterType == DataGridFilterType.Boolean)
        {
            <label class="flex items-center gap-2 text-sm">
                <Checkbox Checked="@_boolValue" CheckedChanged="@OnBoolChanged" />
                <span>@(Column?.Title ?? "Value")</span>
            </label>
        }
        else if (Column?.FilterType == DataGridFilterType.Select)
        {
            @* Faceted (multi-select) mode. A checkbox facet has no notion of an
               operator, so we deliberately DON'T render the operator <Select> here,
               and there is exactly ONE Apply/Clear row (the shared one below). The
               previous layout showed a redundant operator dropdown AND a Select-all
               / Clear helper row that read as a duplicate Apply/Clear (user report).
               This mirrors the shadcn faceted-filter: just the list + a single
               Apply/Clear. *@
            <div class="max-h-40 overflow-auto space-y-1">
                @if (FilterOptions is not null)
                {
                    @foreach (var option in FilterOptions)
                    {
                        <label class="flex items-center gap-2 text-sm py-0.5">
                            <Checkbox Checked="@(_selectedOptions.Contains(option.Value?.ToString() ?? ""))"
                                      CheckedChanged="@(v => ToggleOption(option.Value?.ToString() ?? "", v))" />
                            <span>@option.Label</span>
                        </label>
                    }
                }
            </div>
        }
        else
        {
            <Select Value="@_selectedOperator.ToString()" ValueChanged="@OnOperatorSelected">
                @* The operator combobox is an icon-free, value-only trigger; without
                   an explicit name a screen reader announces it as an unlabeled
                   "combobox" (battle-test #65). aria-label gives it a stable name
                   tied to the filter's operator role. *@
                <SelectTrigger Class="h-8 w-full" aria-label="@L["Filter.Operator"]">
                    <span class="truncate text-sm">@GetOperatorLabel(_selectedOperator)</span>
                </SelectTrigger>
                <SelectContent>
                    @foreach (var op in GetAvailableOperators())
                    {
                        <SelectItem Value="@op.ToString()">@GetOperatorLabel(op)</SelectItem>
                    }
                </SelectContent>
            </Select>

            @if (Column?.FilterType == DataGridFilterType.Number)
            {
                @* @onkeydown:stopPropagation keeps Arrow/Space/Enter inside the
                   number input from bubbling to the host <th>'s keydown handler,
                   which would otherwise move the grid's roving focus while the
                   user is typing/stepping a filter value (battle-test #12). *@
                <input type="number"
                       class="h-8 w-full rounded-md border border-input bg-transparent px-3 text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                       placeholder="@L["Filter.ValuePlaceholder"]"
                       value="@_filterValue"
                       @oninput="OnValueInput"
                       @onkeydown:stopPropagation="true" />
                @if (_selectedOperator == FilterOperator.Between)
                {
                    <input type="number"
                           class="h-8 w-full rounded-md border border-input bg-transparent px-3 text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                           placeholder="@L["Filter.ToValuePlaceholder"]"
                           value="@_filterValueTo"
                           @oninput="OnValueToInput"
                           @onkeydown:stopPropagation="true" />
                }
            }
            else if (Column?.FilterType == DataGridFilterType.Date)
            {
                @* Same leak as the Number input: a Date input's Arrow keys (which
                   step day/month/year) and Space/Enter must not reach the host
                   <th> keyboard handler (battle-test #12). *@
                <input type="date"
                       class="h-8 w-full rounded-md border border-input bg-transparent px-3 text-sm focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                       value="@_filterValue"
                       @oninput="OnValueInput"
                       @onkeydown:stopPropagation="true" />
                @if (_selectedOperator == FilterOperator.Between)
                {
                    <input type="date"
                           class="h-8 w-full rounded-md border border-input bg-transparent px-3 text-sm focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                           value="@_filterValueTo"
                           @oninput="OnValueToInput"
                           @onkeydown:stopPropagation="true" />
                }
            }
            else
            {
                <input type="text"
                       class="h-8 w-full rounded-md border border-input bg-transparent px-3 text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                       placeholder="@L["Filter.ValuePlaceholder"]"
                       value="@_filterValue"
                       @oninput="OnValueInput"
                       @onkeydown:stopPropagation="true" />
            }
        }

        <div class="flex items-center gap-2 pt-1">
            <button type="button"
                    class="flex-1 h-8 rounded-md bg-primary text-primary-foreground text-sm font-medium hover:bg-primary/90 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                    @onclick="Apply">
                @L["Filter.Apply"]
            </button>
            <button type="button"
                    class="flex-1 h-8 rounded-md border border-input bg-background text-sm hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                    @onclick="Clear">
                @L["Filter.Clear"]
            </button>
        </div>
    </div>
    }
</div>

@code {
    [Parameter] public DataGridColumn<TItem>? Column { get; set; }
    [Parameter] public List<FilterOption>? FilterOptions { get; set; }
    [Parameter] public FilterDescriptor? CurrentFilter { get; set; }
    [Parameter] public EventCallback<FilterDescriptor?> OnApply { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // overflow-hidden is required so descendant hover/selected backgrounds
    // (e.g. inside a custom FilterTemplate) get clipped by the rounded-lg
    // corners — CSS border-radius alone only rounds the box itself, not its
    // children. min-w-64 (was w-64) lets a wider FilterTemplate grow the
    // popover instead of horizontally overflowing past the rounded edge.
    private string CssClass => $"min-w-64 rounded-lg border border-border/40 bg-popover text-popover-foreground shadow-md overflow-hidden {Class}".Trim();

    private FilterOperator _selectedOperator = FilterOperator.Contains;
    private string? _filterValue;
    private string? _filterValueTo;
    private bool _boolValue;
    private HashSet<string> _selectedOptions = new();

    // Seed the draft once per popover lifetime. The header cell re-creates this
    // component every time the filter popover opens, so OnParametersSet runs on a
    // fresh instance per open — we hydrate the editor from the column's ACTIVE
    // filter (CurrentFilter) so reopening shows the applied criteria instead of a
    // blank form, and we DON'T re-stomp the draft on later re-renders (typing,
    // operator change) which previously reset Number/Date back to Equals on every
    // keystroke.
    private bool _seeded;

    protected override void OnParametersSet()
    {
        if (_seeded) return;
        _seeded = true;

        // Default operator per filter type (used when there's no active filter).
        _selectedOperator = Column?.FilterType switch
        {
            DataGridFilterType.Number => FilterOperator.Equals,
            DataGridFilterType.Date => FilterOperator.Equals,
            DataGridFilterType.Select => FilterOperator.Contains,
            DataGridFilterType.Boolean => FilterOperator.Equals,
            _ => FilterOperator.Contains,
        };

        // Clamp the type-default into the operators the column actually permits.
        // The operator <Select> dropdown is populated from GetAvailableOperators()
        // (which intersects with Column.Operators), so a type-default the column
        // disallows would otherwise sit selected-but-not-in-the-list and apply
        // silently on a bare Apply (battle-test #11).
        var available = GetAvailableOperators();
        if (available.Count > 0 && !available.Contains(_selectedOperator))
            _selectedOperator = available[0];

        // Hydrate from the column's currently-applied filter, if any. CurrentFilter
        // always carries the real applied operator (including Contains, which is the
        // enum's default value), so assign it unconditionally.
        if (CurrentFilter is not null)
        {
            _selectedOperator = CurrentFilter.Operator;

            // Same clamp for a hydrated operator the column no longer permits.
            if (available.Count > 0 && !available.Contains(_selectedOperator))
                _selectedOperator = available[0];

            switch (Column?.FilterType)
            {
                case DataGridFilterType.Boolean:
                    _boolValue = CurrentFilter.Value is bool b
                        ? b
                        : bool.TryParse(CurrentFilter.Value?.ToString(), out var pb) && pb;
                    break;
                case DataGridFilterType.Select:
                    var joined = CurrentFilter.Value?.ToString();
                    _selectedOptions = string.IsNullOrEmpty(joined)
                        ? new HashSet<string>()
                        : new HashSet<string>(joined.Split(',', StringSplitOptions.RemoveEmptyEntries));
                    break;
                default:
                    _filterValue = CurrentFilter.Value?.ToString();
                    _filterValueTo = CurrentFilter.ValueTo?.ToString();
                    break;
            }
        }
    }

    private void OnOperatorSelected(string value)
    {
        if (Enum.TryParse<FilterOperator>(value, out var op))
        {
            _selectedOperator = op;
        }
    }

    private void OnValueInput(ChangeEventArgs e)
    {
        _filterValue = e.Value?.ToString();
    }

    private void OnValueToInput(ChangeEventArgs e)
    {
        _filterValueTo = e.Value?.ToString();
    }

    private void OnBoolChanged(bool value)
    {
        _boolValue = value;
    }

    private void ToggleOption(string value, bool isChecked)
    {
        if (isChecked)
            _selectedOptions.Add(value);
        else
            _selectedOptions.Remove(value);
    }

    private async Task Apply()
    {
        if (Column?.Field is null) return;

        object? filterValue;
        if (Column.FilterType == DataGridFilterType.Boolean)
        {
            filterValue = _boolValue;
            _selectedOperator = FilterOperator.Equals;
        }
        else if (Column.FilterType == DataGridFilterType.Select)
        {
            // A Select filter with zero options checked is meaningless: the
            // join would be "" and the Evaluate() "no options => match all"
            // rule would surface it as an ACTIVE filter that matches every row
            // (battle-test #10). Treat applying an empty selection as a CLEAR
            // so the column doesn't show a phantom-active filter chip.
            if (_selectedOptions.Count == 0)
            {
                await OnApply.InvokeAsync(null);
                return;
            }
            filterValue = string.Join(",", _selectedOptions);
            // Don't clobber a hydrated operator the Select filter legitimately
            // supports (Contains/Equals) — reopening an Equals filter and pressing
            // Apply must not silently flip it to Contains. Only coerce operators
            // that don't apply to a Select filter.
            if (_selectedOperator is not (FilterOperator.Contains or FilterOperator.Equals))
                _selectedOperator = FilterOperator.Contains;
        }
        else
        {
            filterValue = _filterValue;
        }

        var descriptor = new FilterDescriptor(
            Column.Field,
            _selectedOperator,
            filterValue,
            _filterValueTo,
            Column.FilterType
        );

        await OnApply.InvokeAsync(descriptor);
    }

    private async Task Clear()
    {
        _filterValue = null;
        _filterValueTo = null;
        _boolValue = false;
        _selectedOptions.Clear();
        await OnApply.InvokeAsync(null);
    }

    private List<FilterOperator> GetAvailableOperators()
    {
        var defaults = Column?.FilterType switch
        {
            DataGridFilterType.Number => new List<FilterOperator>
            {
                FilterOperator.Equals, FilterOperator.NotEquals,
                FilterOperator.GreaterThan, FilterOperator.GreaterThanOrEqual,
                FilterOperator.LessThan, FilterOperator.LessThanOrEqual,
                FilterOperator.Between, FilterOperator.IsEmpty, FilterOperator.IsNotEmpty
            },
            DataGridFilterType.Date => new List<FilterOperator>
            {
                FilterOperator.Equals, FilterOperator.NotEquals,
                FilterOperator.GreaterThan, FilterOperator.GreaterThanOrEqual,
                FilterOperator.LessThan, FilterOperator.LessThanOrEqual,
                FilterOperator.Between, FilterOperator.IsEmpty, FilterOperator.IsNotEmpty
            },
            DataGridFilterType.Select => new List<FilterOperator>
            {
                FilterOperator.Contains, FilterOperator.Equals
            },
            _ => new List<FilterOperator>
            {
                FilterOperator.Contains, FilterOperator.NotContains,
                FilterOperator.Equals, FilterOperator.NotEquals,
                FilterOperator.StartsWith, FilterOperator.EndsWith,
                FilterOperator.IsEmpty, FilterOperator.IsNotEmpty
            }
        };

        // If the column restricts operators, intersect with the default set so
        // unsupported combinations (e.g. StartsWith on a Number) aren't surfaced.
        if (Column?.Operators is { Count: > 0 } whitelist)
        {
            var allowed = new HashSet<FilterOperator>(whitelist);
            var filtered = defaults.Where(o => allowed.Contains(o)).ToList();
            // If the intersection is empty, fall back to the whitelist verbatim
            // (consumer clearly wants those operators even if we think they're odd).
            return filtered.Count > 0 ? filtered : whitelist;
        }

        return defaults;
    }

    private string GetOperatorLabel(FilterOperator op) => op switch
    {
        FilterOperator.Contains => L["Filter.Contains"],
        FilterOperator.NotContains => L["Filter.DoesNotContain"],
        FilterOperator.Equals => L["Filter.Equals"],
        FilterOperator.NotEquals => L["Filter.NotEquals"],
        FilterOperator.StartsWith => L["Filter.StartsWith"],
        FilterOperator.EndsWith => L["Filter.EndsWith"],
        FilterOperator.GreaterThan => L["Filter.GreaterThan"],
        FilterOperator.GreaterThanOrEqual => L["Filter.GreaterThanOrEqual"],
        FilterOperator.LessThan => L["Filter.LessThan"],
        FilterOperator.LessThanOrEqual => L["Filter.LessThanOrEqual"],
        FilterOperator.IsEmpty => L["Filter.IsEmpty"],
        FilterOperator.IsNotEmpty => L["Filter.IsNotEmpty"],
        FilterOperator.Between => L["Filter.Between"],
        _ => op.ToString()
    };
}

@namespace Lumeo
@typeparam TItem

@*  Wraps a contiguous run of <DataGridColumnDef>s under a labelled parent header.
    The grid renders a second <tr> above the data-column row with a single <th>
    spanning the grouped columns via colspan, matching DevExpress / Telerik /
    MUI X / AG Grid's "grouped headers" feature.

    Usage:
        <DataGridColumnGroup TItem="Sale" Label="Pricing">
            <DataGridColumnDef Title="Revenue"  Field="Revenue"  Format="C0" />
            <DataGridColumnDef Title="Cost"     Field="Cost"     Format="C0" />
            <DataGridColumnDef Title="Margin %" Field="Margin"   Format="P0" />
        </DataGridColumnGroup>

    The group registers itself with the parent grid and cascades its id to its
    DataGridColumnDef children. The header row stays flat — colspan handles the
    visual nesting — so existing row + body rendering is untouched. *@

<CascadingValue Value="_groupId" Name="ColumnGroupId" IsFixed="true">
    @ChildContent
</CascadingValue>

@code {
    [CascadingParameter] private DataGrid<TItem>? ParentGrid { get; set; }

    /// <summary>Header label shown in the spanning <c>th</c> above the grouped columns.</summary>
    [Parameter] public string Label { get; set; } = "";

    /// <summary>Extra classes for the spanning header cell — theming hook for the group.</summary>
    [Parameter] public string? HeaderClass { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }

    // Stable per-instance id so the cascaded ColumnGroupId on child DataGridColumnDefs
    // is matched to one specific DataGridColumnGroup<TItem> registration.
    // LumeoIds isn't in this assembly (lives in core Lumeo); a plain Guid suffix is fine
    // since the id is internal — only used to correlate the group header with its child
    // columns' ColumnGroupId cascade.
    private readonly string _groupId = "dgcg-" + Guid.NewGuid().ToString("N")[..8];

    protected override void OnInitialized()
        => ParentGrid?.RegisterColumnGroup(new DataGridColumnGroupInfo(_groupId, Label, HeaderClass));
}

@namespace Lumeo
@typeparam TItem
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Lumeo.Services.ComponentInteropService Interop

<div class="@CssClass" @attributes="AdditionalAttributes">
    <div class="p-3 space-y-1">
        <div class="text-xs font-medium text-muted-foreground uppercase tracking-wider mb-2">
            @L["DataGrid.ToggleColumns"]
        </div>
        @{
            // Bind the SortableList to an in-place mutable buffer so its
            // OnDrop / HandleTouchDrop callbacks have a stable list to update.
            // We rebuild from Columns whenever the upstream column set changes
            // (see OnParametersSet) — drag-reorder only ever fires the
            // OnColumnReorder callback, the parent owns the canonical order.
        }
        <SortableList TItem="DataGridColumn<TItem>"
                      Items="_buffer"
                      ItemsChanged="HandleSortChanged"
                      Key="@(c => c.Id)"
                      Class="flex flex-col gap-1">
            <ItemTemplate Context="column">
                <div class="flex items-center gap-2 flex-1 min-w-0">
                    @* The whole row is the toggle. Lumeo's Checkbox is a
                       button[role=checkbox], which a <label for> cannot activate — so
                       wrapping it in a <label> left the text (and most of the row) dead
                       to clicks. We render the row itself as a role=checkbox button with
                       a presentational check glyph (aria-hidden) so clicking anywhere on
                       the label region toggles, with proper aria-checked semantics. The
                       pin control stays a sibling button (can't nest interactive els). *@
                    <button type="button"
                            role="checkbox"
                            aria-checked="@(column.Visible ? "true" : "false")"
                            class="flex items-center gap-2 text-sm cursor-pointer flex-1 min-w-0 text-start rounded focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                            @onclick="@(() => ToggleColumn(column, !column.Visible))">
                        <span aria-hidden="true"
                              class="@($"inline-flex items-center justify-center h-4 w-4 shrink-0 rounded border transition-colors {(column.Visible ? "bg-primary border-primary text-primary-foreground" : "border-primary/60 bg-background")}")">
                            @if (column.Visible)
                            {
                                <svg class="pointer-events-none h-2.5 w-2.5" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="2.75" stroke-linecap="round" stroke-linejoin="round">
                                    <polyline points="2.5,6.5 5,8.5 9.5,3.5" />
                                </svg>
                            }
                        </span>
                        <span class="truncate">@(column.Title ?? column.Field ?? "Column")</span>
                    </button>
                    @if (column.Pinnable)
                    {
                        <div class="relative shrink-0">
                            <Tooltip>
                                <TooltipTrigger AsChild>
                                    <ChildContentSlot Context="slot">
                                        <button type="button"
                                                id="@PinTriggerId(column.Id)"
                                                class="@(column.Pin != PinDirection.None
                                                    ? "inline-flex items-center justify-center h-6 w-6 rounded bg-primary/15 text-primary hover:bg-primary/20 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                                                    : "inline-flex items-center justify-center h-6 w-6 rounded text-muted-foreground hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1")"
                                                aria-label="@L["DataGrid.PinColumn"]"
                                                @onclick="@(() => TogglePinMenu(column.Id))"
                                                @onclick:stopPropagation="true"
                                                @attributes="slot.Attributes">
                                            <SvgGlyph Svg="@(LumeoIcons.Pin)" class="@(column.Pin != PinDirection.None ? "h-3.5 w-3.5 rotate-45" : "h-3.5 w-3.5")" />
                                        </button>
                                    </ChildContentSlot>
                                </TooltipTrigger>
                                <TooltipContent>@L["DataGrid.PinColumn"]</TooltipContent>
                            </Tooltip>
                            @if (_openPinMenu == column.Id)
                            {
                                <div id="@PinMenuId(column.Id)"
                                     class="absolute right-0 top-full mt-1 z-50 min-w-[140px] rounded-md border border-border/40 bg-popover text-popover-foreground shadow-md p-1"
                                     @onclick:stopPropagation="true"
                                     @onkeydown="@(e => HandlePinMenuKeyDown(e, column.Id))">
                                    <button type="button"
                                            class="w-full flex items-center gap-2 px-2 py-1.5 rounded text-sm text-start hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:bg-accent disabled:opacity-50 disabled:cursor-not-allowed"
                                            disabled="@(column.Pin == PinDirection.Left)"
                                            @onclick="@(() => PinColumn(column, PinDirection.Left))">
                                        <SvgGlyph Svg="@(LumeoIcons.ChevronsLeft)" class="h-3.5 w-3.5" />
                                        <span>@L["DataGrid.PinLeft"]</span>
                                    </button>
                                    <button type="button"
                                            class="w-full flex items-center gap-2 px-2 py-1.5 rounded text-sm text-start hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:bg-accent disabled:opacity-50 disabled:cursor-not-allowed"
                                            disabled="@(column.Pin == PinDirection.Right)"
                                            @onclick="@(() => PinColumn(column, PinDirection.Right))">
                                        <SvgGlyph Svg="@(LumeoIcons.ChevronsRight)" class="h-3.5 w-3.5" />
                                        <span>@L["DataGrid.PinRight"]</span>
                                    </button>
                                    <button type="button"
                                            class="w-full flex items-center gap-2 px-2 py-1.5 rounded text-sm text-start hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:bg-accent disabled:opacity-50 disabled:cursor-not-allowed"
                                            disabled="@(column.Pin == PinDirection.None)"
                                            @onclick="@(() => PinColumn(column, PinDirection.None))">
                                        <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3.5 w-3.5" />
                                        <span>@L["DataGrid.Unpin"]</span>
                                    </button>
                                </div>
                            }
                        </div>
                    }
                </div>
            </ItemTemplate>
        </SortableList>
    </div>
</div>

@code {
    [Parameter] public IReadOnlyList<DataGridColumn<TItem>> Columns { get; set; } = Array.Empty<DataGridColumn<TItem>>();
    [Parameter] public EventCallback<DataGridColumn<TItem>> OnColumnToggle { get; set; }
    [Parameter] public EventCallback<ColumnReorderEventArgs> OnColumnReorder { get; set; }
    [Parameter] public EventCallback<ColumnPinEventArgs> OnColumnPin { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"w-64 rounded-lg border border-border/40 bg-popover text-popover-foreground shadow-md {Class}".Trim();

    // Mutable buffer for SortableList. We keep it in sync with the readonly
    // Columns parameter; the drag callback runs locally on this buffer, then
    // we emit a single ColumnReorderEventArgs (oldIndex, newIndex) so the
    // parent's reorder pipeline stays the keyboard/UI source of truth.
    private List<DataGridColumn<TItem>> _buffer = new();
    private string? _openPinMenu;
    private bool _pinMenuClickOutsideRegistered;

    // Stable per-column IDs for click-outside registration.
    private string PinTriggerId(string columnId) => $"dg-pin-trigger-{columnId}";
    private string PinMenuId(string columnId) => $"dg-pin-menu-{columnId}";

    protected override void OnParametersSet()
    {
        _buffer = Columns.ToList();
    }

    private async Task ToggleColumn(DataGridColumn<TItem> column, bool visible)
    {
        column.Visible = visible;
        await OnColumnToggle.InvokeAsync(column);
    }

    private async Task HandleSortChanged(List<DataGridColumn<TItem>> reordered)
    {
        // Diff old -> new to recover the (oldIndex, newIndex) move. SortableList
        // performs a single Remove+Insert per drop, so exactly one column moved.
        var oldOrder = Columns.ToList();
        if (reordered.Count != oldOrder.Count) return;

        int movedNewIndex = -1;
        for (int i = 0; i < reordered.Count; i++)
        {
            if (!ReferenceEquals(reordered[i], oldOrder[i]))
            {
                movedNewIndex = i;
                break;
            }
        }
        if (movedNewIndex < 0) return;

        var moved = reordered[movedNewIndex];
        var oldIndex = oldOrder.FindIndex(c => ReferenceEquals(c, moved));
        if (oldIndex < 0 || oldIndex == movedNewIndex) return;

        _buffer = reordered; // optimistic — SortableList already shows this order
        var args = new ColumnReorderEventArgs(moved.Id, oldIndex, movedNewIndex);
        await OnColumnReorder.InvokeAsync(args);

        // HandleColumnReorder (DataGrid.HandleColumnReorder) mutates the grid's own
        // column list SYNCHRONOUSLY before this await resumes — whether it applies
        // the move (ReorderColumnsPreservingLocked + RefreshVisibleColumns) or
        // rejects it (locked source column, cross-pin-partition move, or a
        // redirect-to-nothing no-op) has already fully happened by now, regardless
        // of when/whether Blazor gets around to actually re-rendering us. A
        // rejection deliberately skips StateHasChanged (round-5's no-op guard, so a
        // no-op drag doesn't pay for an event/autosave/FLIP-animation/rerender it
        // didn't need) — so without this check, a rejected drag left the panel
        // permanently showing the optimistically-applied WRONG order until some
        // unrelated re-render happened to reset it via OnParametersSet (round-6
        // finding). `Columns` is a live ReadOnlyCollection view over that same
        // mutable list (see DataGrid.EffectiveColumns), so re-reading it here — even
        // through this still-stale parameter reference — reflects whatever DID or
        // DIDN'T change. Snap the buffer back to it on any mismatch; a genuine
        // accept still matches (or gets corrected again, harmlessly, once the real
        // re-render's OnParametersSet lands the authoritative post-repartition order).
        if (!_buffer.SequenceEqual(Columns))
            _buffer = Columns.ToList();
    }

    private async Task TogglePinMenu(string columnId)
    {
        if (_openPinMenu == columnId)
        {
            await ClosePinMenuAsync();
        }
        else
        {
            // Close any previously open menu first.
            if (_openPinMenu is not null)
                await ClosePinMenuAsync();

            _openPinMenu = columnId;
            StateHasChanged();
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_openPinMenu is not null && !_pinMenuClickOutsideRegistered)
        {
            var menuId = PinMenuId(_openPinMenu);
            var triggerId = PinTriggerId(_openPinMenu);
            try
            {
                await Interop.RegisterClickOutside(menuId, triggerId, async () =>
                {
                    _openPinMenu = null;
                    _pinMenuClickOutsideRegistered = false;
                    await InvokeAsync(StateHasChanged);
                });
                _pinMenuClickOutsideRegistered = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        else if (_openPinMenu is null && _pinMenuClickOutsideRegistered)
        {
            await UnregisterPinMenuClickOutsideAsync();
        }
    }

    private async Task ClosePinMenuAsync()
    {
        _openPinMenu = null;
        if (_pinMenuClickOutsideRegistered)
            await UnregisterPinMenuClickOutsideAsync();
        StateHasChanged();
    }

    private async Task UnregisterPinMenuClickOutsideAsync()
    {
        _pinMenuClickOutsideRegistered = false;
        // We need to unregister for each column; use a snapshot of the last open menu id.
        // Since _openPinMenu is already null here, iterate the column list and try all.
        foreach (var col in _buffer)
        {
            try { await Interop.UnregisterClickOutside(PinMenuId(col.Id)); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch { /* element may not have been registered */ }
        }
    }

    private void HandlePinMenuKeyDown(KeyboardEventArgs e, string columnId)
    {
        if (e.Key == "Escape" && _openPinMenu == columnId)
        {
            _ = ClosePinMenuAsync();
        }
    }

    private async Task PinColumn(DataGridColumn<TItem> column, PinDirection direction)
    {
        await ClosePinMenuAsync();
        await OnColumnPin.InvokeAsync(new ColumnPinEventArgs(column.Id, direction));
    }

    public async ValueTask DisposeAsync()
    {
        if (_pinMenuClickOutsideRegistered)
        {
            await UnregisterPinMenuClickOutsideAsync();
        }
    }
}

using System.Globalization;
using Microsoft.AspNetCore.Components;
