@code {
    [CascadingParameter] public DataGridToolbarContext<TItem>? Context { get; set; }

    private bool _columnPanelOpen;
    private bool _clickOutsideRegistered;
    private readonly string _triggerButtonId = $"dg-columns-trigger-{Guid.NewGuid():N}";
    private readonly string _menuId = $"dg-columns-menu-{Guid.NewGuid():N}";

    private async Task ToggleColumnPanel()
    {
        if (_columnPanelOpen)
            await CloseMenuAsync();
        else
            _columnPanelOpen = true;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_columnPanelOpen && !_clickOutsideRegistered && Context?.Interop is not null)
        {
            try
            {
                await Context.Interop.RegisterClickOutside(_menuId, _triggerButtonId, async () =>
                {
                    _columnPanelOpen = false;
                    _clickOutsideRegistered = false;
                    await InvokeAsync(StateHasChanged);
                });
                _clickOutsideRegistered = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        else if (!_columnPanelOpen && _clickOutsideRegistered)
        {
            await UnregisterClickOutsideAsync();
        }
    }

    private async Task CloseMenuAsync()
    {
        _columnPanelOpen = false;
        if (_clickOutsideRegistered)
            await UnregisterClickOutsideAsync();
        StateHasChanged();
    }

    private async Task UnregisterClickOutsideAsync()
    {
        _clickOutsideRegistered = false;
        if (Context?.Interop is not null)
        {
            try { await Context.Interop.UnregisterClickOutside(_menuId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    private void HandleMenuKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
            _ = CloseMenuAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_clickOutsideRegistered)
            await UnregisterClickOutsideAsync();
    }
}

