@code {
    [CascadingParameter] public DataGridToolbarContext<TItem>? Context { get; set; }

    private bool _exportMenuOpen;
    private bool _clickOutsideRegistered;
    private readonly string _triggerButtonId = $"dg-export-trigger-{Guid.NewGuid():N}";
    private readonly string _menuId = $"dg-export-menu-{Guid.NewGuid():N}";

    private async Task ToggleExportMenu()
    {
        if (_exportMenuOpen)
            await CloseMenuAsync();
        else
            _exportMenuOpen = true;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_exportMenuOpen && !_clickOutsideRegistered && Context?.Interop is not null)
        {
            try
            {
                await Context.Interop.RegisterClickOutside(_menuId, _triggerButtonId, async () =>
                {
                    _exportMenuOpen = false;
                    _clickOutsideRegistered = false;
                    await InvokeAsync(StateHasChanged);
                });
                _clickOutsideRegistered = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        else if (!_exportMenuOpen && _clickOutsideRegistered)
        {
            await UnregisterClickOutsideAsync();
        }
    }

    private async Task CloseMenuAsync()
    {
        _exportMenuOpen = false;
        if (_clickOutsideRegistered)
            await UnregisterClickOutsideAsync();
        StateHasChanged();
    }

    private async Task UnregisterClickOutsideAsync()
    {
        _clickOutsideRegistered = false;
        if (Context?.Interop is not null)
        {
            try { await Context.Interop.UnregisterClickOutside(_menuId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    private void HandleMenuKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
            _ = CloseMenuAsync();
    }

    private async Task Export(string format)
    {
        if (Context is null) return;
        await CloseMenuAsync();
        await Context.OnExport.InvokeAsync(format);
    }

    public async ValueTask DisposeAsync()
    {
        if (_clickOutsideRegistered)
            await UnregisterClickOutsideAsync();
    }
}

